/* =========================================================
Nombre completo: xlsx.min.js
Ruta o ubicación: /Curriculo/libs/xlsx.min.js
Función o funciones:
- Cargar XLSX desde la dependencia local instalada en node_modules.
- Exponer window.XLSX antes de que subir.excel.js intente usarla.
- Crear la promesa global window.__XLSXReady para esperar la carga.
- Usar CDN únicamente como respaldo opcional cuando la copia local no exista.
- Permitir que Electron lea Excel sin depender de internet durante el uso normal.
========================================================= */

(function (window, document) {
  "use strict";

  var LIB_NAME = "XLSX";
  var READY_NAME = "__XLSXReady";
  var TIMEOUT_MS = 12000;
  var SCRIPT_ACTUAL = document.currentScript && document.currentScript.src
    ? document.currentScript.src
    : window.location.href;

  var LOCAL_URL = new URL(
    "../node_modules/xlsx/dist/xlsx.full.min.js",
    SCRIPT_ACTUAL
  ).href;

  var CDN_LIST = [
    "https://cdn.jsdelivr.net/npm/xlsx@0.18.5/dist/xlsx.full.min.js",
    "https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js",
    "https://unpkg.com/xlsx@0.18.5/dist/xlsx.full.min.js"
  ];

  if (window[LIB_NAME]) {
    window[READY_NAME] = Promise.resolve(window[LIB_NAME]);
    return;
  }

  if (window[READY_NAME]) {
    return;
  }

  function cargarScript(src) {
    return new Promise(function (resolve, reject) {
      var finalizado = false;
      var timer = null;
      var script = document.createElement("script");

      function limpiar() {
        if (timer) clearTimeout(timer);
      }

      function terminarConError(error) {
        if (finalizado) return;
        finalizado = true;
        limpiar();

        try {
          if (script.parentNode) script.parentNode.removeChild(script);
        } catch (e) {}

        reject(error);
      }

      function terminarOK() {
        if (finalizado) return;
        finalizado = true;
        limpiar();
        resolve(window[LIB_NAME]);
      }

      script.src = src;
      script.async = false;
      script.defer = false;

      script.onload = function () {
        if (window[LIB_NAME]) {
          terminarOK();
        } else {
          terminarConError(new Error(
            "El script XLSX cargó, pero window.XLSX no está disponible."
          ));
        }
      };

      script.onerror = function () {
        terminarConError(new Error("No se pudo cargar XLSX desde: " + src));
      };

      timer = setTimeout(function () {
        if (!window[LIB_NAME]) {
          terminarConError(new Error(
            "Tiempo agotado cargando XLSX desde: " + src
          ));
        }
      }, TIMEOUT_MS);

      document.head.appendChild(script);
    });
  }

  async function cargarXLSX() {
    var errores = [];

    try {
      await cargarScript(LOCAL_URL);
      return window[LIB_NAME];
    } catch (errorLocal) {
      errores.push("Copia local: " + errorLocal.message);
    }

    for (var i = 0; i < CDN_LIST.length; i += 1) {
      try {
        await cargarScript(CDN_LIST[i]);
        return window[LIB_NAME];
      } catch (errorCDN) {
        errores.push(errorCDN.message);
      }
    }

    throw new Error(
      "No se pudo cargar XLSX. Ejecuta npm install para instalar la copia local. " +
      "Detalle: " + errores.join(" | ")
    );
  }

  window[READY_NAME] = cargarXLSX();
})(window, document);
